import React from 'react';
import ReactDOM from 'react-dom';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import './index.css';
import App from './App';
import ChessLikeWrapper from './components/ChessLikeWrapper';
import BallyGameBoy from './components/BallyGameBoy';
import BallyGameBoat from './components/BallyGameBoat';
import FairyLand from './components/FairyLand';
import BallyTown from './components/BallyTown';
import BallyNeo from './components/BallyNeo';
import BallyMurphius from './components/BallyMurphius';

ReactDOM.render(
  <Router>
    <Switch>
      <Route path="/chesslike" component={ChessLikeWrapper} />
      <Route path="/ballygameboy" component={BallyGameBoy} />
      <Route path="/ballygameboat" component={BallyGameBoat} />
      <Route path="/fairyland" component={FairyLand} />
      <Route path="/ballytown" component={BallyTown} />
      <Route path="/ballyneo" component={BallyNeo} />
      <Route path="/ballymurphius" component={BallyMurphius} />
      <Route path="/" component={App} />
    </Switch>
  </Router>,
  document.getElementById('root')
);
